    qc.cancelQueries();
    qc.clear();
    if (typeof window !== 'undefined') {
      ['admin_token', 'auth_token', 'user_info', 'admin_user', 'employee_user'].forEach(
        (k) => localStorage.removeItem(k),
      );
    }
    router.push('/admin/login');
  };
}
