import { useQuery } from '@tanstack/react-query';
import { apiClient } from '@/lib/api/client';

export interface DashboardStatsFilters {
  role: string;
  /** Note: BE param name is `salary_month`, not `month` (verified Step 3.0.2) */
  salary_month?: string;
}

export function useDashboardStatsQuery(filters: DashboardStatsFilters) {
  return useQuery({
    queryKey: ['dashboard-stats', filters],
    queryFn: ({ signal }) => {
      const params = new URLSearchParams({ role: filters.role });
      if (filters.salary_month) params.set('salary_month', filters.salary_month);
      return apiClient.get<DashboardStats>(
        `${ENDPOINTS.dashboard.stats}?${params.toString()}`,
        { signal },
      );
    },
    staleTime: 30_000,
  });
}

