  return useQuery({
    queryKey: ['signature-progress', salaryMonth],
    queryFn: ({ signal }) =>
      apiClient.get(ENDPOINTS.payroll.signatureProgress(salaryMonth), { signal }),
    enabled: Boolean(salaryMonth),
    staleTime: 30_000,
  });
}

